import{_ as a,o as r,c as d,ag as e}from"./chunks/framework.CxZWPeXl.js";const c=JSON.parse('{"title":"儀表板","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/dashboard.md","filePath":"zh-TW/dashboard.md"}'),l={name:"zh-TW/dashboard.md"};function o(i,t,h,n,s,u){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="儀表板" tabindex="-1">儀表板 <a class="header-anchor" href="#儀表板" aria-label="Permalink to &quot;儀表板&quot;">​</a></h1><blockquote><p>一目了然掌握你的練習進度與學習成果</p></blockquote><h2 id="頁面概覽" tabindex="-1">頁面概覽 <a class="header-anchor" href="#頁面概覽" aria-label="Permalink to &quot;頁面概覽&quot;">​</a></h2><p>儀表板是登入後的首頁，提供個人學習概況與快速操作入口。頁面由上而下分為兩個區域：<strong>統計卡片區</strong> 與 <strong>近期練習紀錄</strong>。同時，上方導覽列提供了核心系統操作功能。</p><h2 id="頂部導覽列與系統控制" tabindex="-1">頂部導覽列與系統控制 <a class="header-anchor" href="#頂部導覽列與系統控制" aria-label="Permalink to &quot;頂部導覽列與系統控制&quot;">​</a></h2><ul><li><strong>Logo/首頁：</strong> 從任何位置返回儀表板。</li><li><strong>語系切換：</strong> 切換介面語言（支援繁體中文與越南語）。</li><li><strong>AI 知識助手：</strong> 開啟側邊面板，提供支援業務人員的各種工具與範例。</li><li><strong>後台管理系統：</strong> 供具權限之管理員進行系統與提示詞設定。</li><li><strong>登出：</strong> 登出目前的系統會話。</li></ul><h2 id="統計卡片區" tabindex="-1">統計卡片區 <a class="header-anchor" href="#統計卡片區" aria-label="Permalink to &quot;統計卡片區&quot;">​</a></h2><h3 id="開始對話" tabindex="-1">開始對話 <a class="header-anchor" href="#開始對話" aria-label="Permalink to &quot;開始對話&quot;">​</a></h3><ul><li>點擊即可進入對話練習設定頁面，開始新的模擬演練。</li></ul><h3 id="累積練習次數" tabindex="-1">累積練習次數 <a class="header-anchor" href="#累積練習次數" aria-label="Permalink to &quot;累積練習次數&quot;">​</a></h3><ul><li>顯示您截至目前為止展開的所有練習總次數。</li><li>單位：<strong>次</strong></li></ul><h3 id="對話總時間" tabindex="-1">對話總時間 <a class="header-anchor" href="#對話總時間" aria-label="Permalink to &quot;對話總時間&quot;">​</a></h3><ul><li>顯示您所有練習的累計對話時長。</li><li>單位：<strong>小時/分鐘</strong></li></ul><h3 id="連續練習的天數" tabindex="-1">連續練習的天數 <a class="header-anchor" href="#連續練習的天數" aria-label="Permalink to &quot;連續練習的天數&quot;">​</a></h3><ul><li>顯示您連續每日進行練習不中斷的天數紀錄。</li><li>單位：<strong>天</strong>（只要有一天未啟動練習，紀錄就會歸零重新計算）</li></ul><h2 id="近期練習紀錄" tabindex="-1">近期練習紀錄 <a class="header-anchor" href="#近期練習紀錄" aria-label="Permalink to &quot;近期練習紀錄&quot;">​</a></h2><p>顯示最近的練習紀錄列表（預設為 5 筆），並提供詳細的資料與快速操作。</p><h3 id="快速篩選" tabindex="-1">快速篩選 <a class="header-anchor" href="#快速篩選" aria-label="Permalink to &quot;快速篩選&quot;">​</a></h3><table tabindex="0"><thead><tr><th>選項</th><th>說明</th></tr></thead><tbody><tr><td>時鐘圖示（預設）</td><td>顯示最近 5 筆練習紀錄</td></tr><tr><td>今天</td><td>篩選出今日的練習紀錄</td></tr><tr><td>日期選擇器</td><td>依據指定的日期過濾紀錄 (YYYY-MM-DD)</td></tr><tr><td>全部</td><td>跳轉至「練習歷史」頁面，查看完整紀錄</td></tr></tbody></table><h3 id="資料欄位" tabindex="-1">資料欄位 <a class="header-anchor" href="#資料欄位" aria-label="Permalink to &quot;資料欄位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th></tr></thead><tbody><tr><td>日期</td><td>練習進行的日期</td></tr><tr><td>年齡</td><td>客戶角色的年齡</td></tr><tr><td>性別</td><td>客戶角色的性別（男 / 女）</td></tr><tr><td>姓名</td><td>客戶角色的姓名（可點擊查看詳細人物誌）</td></tr><tr><td>職業</td><td>客戶角色的職業</td></tr><tr><td>收入</td><td>客戶角色的收入等級</td></tr><tr><td>達成階段</td><td>該次練習最終達成的最高銷售階段（附帶工具提示說明）</td></tr><tr><td>練習時長</td><td>該次練習的實際對話時長 (分鐘)</td></tr></tbody></table><h3 id="操作按鈕" tabindex="-1">操作按鈕 <a class="header-anchor" href="#操作按鈕" aria-label="Permalink to &quot;操作按鈕&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按鈕</th><th>說明</th></tr></thead><tbody><tr><td>查看評估 (眼睛圖示)</td><td>前往該次練習的詳細評核報告頁面</td></tr><tr><td>重新挑戰 (循環圖示)</td><td>使用完全相同的客戶角色設定，開始一次全新的練習</td></tr><tr><td>繼續練習 (播放圖示)</td><td>接續上次未完成的對話</td></tr></tbody></table><h3 id="人物誌檔案面板-persona-modal" tabindex="-1">人物誌檔案面板 (Persona Modal) <a class="header-anchor" href="#人物誌檔案面板-persona-modal" aria-label="Permalink to &quot;人物誌檔案面板 (Persona Modal)&quot;">​</a></h3><p>在列表中點擊客戶的 <strong>姓名</strong>，將會開啟一個詳細的人物檔案對話框，包含：</p><ul><li><strong>MBTI 人格特質：</strong> 協助您了解客戶的決策與溝通風格（例如：INTJ - 建築師）。</li><li><strong>家庭與教育資訊：</strong> 婚姻狀態、學歷等背景。</li><li><strong>關係設定：</strong> 客戶與業務員當前的熟稔程度。</li><li><strong>「使用此角色重新練習」按鈕：</strong> 直接以該詳細設定啟動新的模擬練習。</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>開始 <a href="./practice.html">對話練習</a></li><li>了解 <a href="./evaluation.html">評量報告</a> 的評核內容</li><li>查看完整的 <a href="./history.html">練習歷史</a></li></ul>',29)])])}const g=a(l,[["render",o]]);export{c as __pageData,g as default};
